129‚Üí### Format Utilities -- Exact Code
130‚Üí
131‚Üí**File: `src/lib/utils/format-utils.ts`**
132‚Üí
133‚Üí```typescript
134‚Üí/**
135‚Üí * Format a price as USD with 2 decimal places.
136‚Üí * Example: 68432.17 ‚Üí "$68,432.17"
137‚Üí */
138‚Üíexport function formatPrice(price: number): string {
139‚Üí  return new Intl.NumberFormat('en-US', {
140‚Üí    style: 'currency',
141‚Üí    currency: 'USD',
142‚Üí    minimumFractionDigits: 2,
143‚Üí    maximumFractionDigits: 2,
144‚Üí  }).format(price);
145‚Üí}
146‚Üí
147‚Üí/**
148‚Üí * Format a percentage with sign and 1 decimal place.
149‚Üí * Example: 2.3 ‚Üí "+2.3%", -1.8 ‚Üí "-1.8%"
150‚Üí */
151‚Üíexport function formatPercent(value: number): string {
152‚Üí  return new Intl.NumberFormat('en-US', {
153‚Üí    style: 'percent',
154‚Üí    minimumFractionDigits: 1,
155‚Üí    maximumFractionDigits: 1,
156‚Üí    signDisplay: 'always',
157‚Üí  }).format(value / 100);
158‚Üí}
159‚Üí
160‚Üí/**
161‚Üí * Format an absolute USD change with sign.
162‚Üí * Example: 1534.22 ‚Üí "+$1,534.22", -892.40 ‚Üí "-$892.40"
163‚Üí */
164‚Üíexport function formatAbsoluteChange(value: number): string {
165‚Üí  return new Intl.NumberFormat('en-US', {
166‚Üí    style: 'currency',
167‚Üí    currency: 'USD',
168‚Üí    minimumFractionDigits: 2,
169‚Üí    maximumFractionDigits: 2,
170‚Üí    signDisplay: 'always',
171‚Üí  }).format(value);
172‚Üí}
173‚Üí
174‚Üí/**
175‚Üí * Format market cap with compact notation.
176‚Üí * Example: 1340000000000 ‚Üí "$1.34T", 892450000000 ‚Üí "$892.45B"
177‚Üí */
178‚Üíexport function formatMarketCap(value: number): string {
179‚Üí  return new Intl.NumberFormat('en-US', {
180‚Üí    style: 'currency',
181‚Üí    currency: 'USD',
182‚Üí    notation: 'compact',
183‚Üí    minimumFractionDigits: 2,
184‚Üí    maximumFractionDigits: 2,
185‚Üí  }).format(value);
186‚Üí}
187‚Üí
188‚Üí/**
189‚Üí * Format a price range with compact notation.
190‚Üí * Example: (66900, 68900) ‚Üí "$66.9K ‚Äî $68.9K"
191‚Üí *
192‚Üí * Note: Intl.NumberFormat compact notation capitalizes the suffix (K, M, B, T).
193‚Üí * The architecture spec shows lowercase "k" but Intl produces uppercase "K".
194‚Üí * Using Intl output as-is to avoid manual string manipulation (per AC #7).
195‚Üí */
196‚Üíexport function formatRange(low: number, high: number): string {
197‚Üí  const formatter = new Intl.NumberFormat('en-US', {
198‚Üí    style: 'currency',
199‚Üí    currency: 'USD',
200‚Üí    notation: 'compact',
201‚Üí    minimumFractionDigits: 1,
202‚Üí    maximumFractionDigits: 1,
203‚Üí  });
204‚Üí  return `${formatter.format(low)} ‚Äî ${formatter.format(high)}`;
205‚Üí}
206‚Üí
207‚Üí/**
208‚Üí * Format a chart tooltip with price and time.
209‚Üí * Example: (68432.17, 1711972200000) ‚Üí "$68,432.17 at 14:30"
210‚Üí */
211‚Üíexport function formatChartTooltip(price: number, timestamp: number): string {
212‚Üí  const formattedPrice = formatPrice(price);
213‚Üí  const formattedTime = new Intl.DateTimeFormat('en-US', {
214‚Üí    hour: '2-digit',
215‚Üí    minute: '2-digit',
216‚Üí    hour12: false,
217‚Üí  }).format(new Date(timestamp));
218‚Üí  return `${formattedPrice} at ${formattedTime}`;
219‚Üí}
220‚Üí```
221‚Üí
222‚Üí**Implementation notes:**
223‚Üí- `formatPercent` divides by 100 because `Intl.NumberFormat` with `style: 'percent'` multiplies the input by 100. The input `value` is already a percentage (e.g., `2.3` means 2.3%), so divide by 100 to get the correct output.
224‚Üí- `formatRange` uses em dash ` ‚Äî ` as separator per UX spec.
225‚Üí- `formatChartTooltip` uses 24-hour time format with `hour12: false` per UX spec ("14:30").
226‚Üí- All functions are pure -- no side effects, no store access, no DOM interaction.
227‚Üí- Each function creates a new `Intl.NumberFormat` instance. For v1, this is acceptable. If profiling shows hot paths, instances can be cached at module scope later.
