    <div
      data-chart-tooltip
      class="absolute z-10 pointer-events-none hidden font-price text-text-primary text-[13px] font-normal leading-[1.1] bg-bg-card border border-white/10 rounded-lg px-3 py-2 whitespace-nowrap"
    ></div>
