</style>

<script>
  import { createChart, AreaSeries } from 'lightweight-charts';
  import type { IChartApi, ISeriesApi, MouseEventParams, SingleValueData } from 'lightweight-charts';
  import { chartStore } from '../lib/stores/chart-store';
  import { CHART_COLORS } from '../lib/theme-constants';
  import { formatChartTooltip } from '../lib/utils/format-utils';
  import type { ChartPoint } from '../lib/types';

  const container = document.querySelector<HTMLDivElement>('[data-chart-container]');
  const tooltipEl = document.querySelector<HTMLDivElement>('[data-chart-tooltip]');

  if (container && tooltipEl) {
    // --- Chart Creation ---
    const chart: IChartApi = createChart(container, {
      autoSize: true,
      layout: {
        background: { color: CHART_COLORS.backgroundColor },
        textColor: CHART_COLORS.textColor,
        attributionLogo: false,
      },
      grid: {
        vertLines: { color: CHART_COLORS.gridLinesColor },
        horzLines: { color: CHART_COLORS.gridLinesColor },
      },
      crosshair: {
        vertLine: { color: CHART_COLORS.crosshairColor, width: 1, style: 3 },
        horzLine: { color: CHART_COLORS.crosshairColor, width: 1, style: 3 },
      },
      rightPriceScale: {
        borderVisible: false,
      },
      timeScale: {
        borderVisible: false,
        timeVisible: true,
        secondsVisible: false,
      },
      handleScroll: false,
      handleScale: false,
    });

    // --- Area Series ---
    const areaSeries: ISeriesApi<'Area'> = chart.addSeries(AreaSeries, {
      lineColor: CHART_COLORS.lineColor,
      topColor: CHART_COLORS.areaTopColor,
      bottomColor: CHART_COLORS.areaBottomColor,
      lineWidth: 2,
      crosshairMarkerVisible: true,
      crosshairMarkerRadius: 4,
      crosshairMarkerBorderColor: CHART_COLORS.lineColor,
      crosshairMarkerBackgroundColor: CHART_COLORS.backgroundColor === 'transparent'
        ? '#12121a'  // bg-card fallback for marker
        : CHART_COLORS.backgroundColor,
    });

    // --- Set aria-hidden on chart canvas ---
    const canvasElements = container.querySelectorAll('canvas');
    canvasElements.forEach((canvas) => {
      canvas.setAttribute('aria-hidden', 'true');
    });

    // --- Crosshair Tooltip ---
    chart.subscribeCrosshairMove((param: MouseEventParams) => {
      if (
        !param.point ||
        !param.time ||
        param.point.x < 0 ||
        param.point.y < 0
      ) {
        tooltipEl.classList.add('hidden');
        return;
      }

      const data = param.seriesData.get(areaSeries) as SingleValueData | undefined;
      if (!data || data.value === undefined) {
        tooltipEl.classList.add('hidden');
        return;
      }

      // Convert time to timestamp for formatChartTooltip
      // lightweight-charts uses UTCTimestamp (seconds since epoch) or BusinessDay
      let timestamp: number;
      if (typeof param.time === 'number') {
        // UTCTimestamp is in seconds ‚Äî convert to milliseconds
        timestamp = param.time * 1000;
      } else {
        // BusinessDay object ‚Äî construct Date
        const { year, month, day } = param.time as { year: number; month: number; day: number };
        timestamp = new Date(year, month - 1, day).getTime();
      }

      tooltipEl.textContent = formatChartTooltip(data.value, timestamp);
      tooltipEl.classList.remove('hidden');

      // Position tooltip near crosshair point
      const containerRect = container.getBoundingClientRect();
      const tooltipWidth = tooltipEl.offsetWidth;
      const tooltipHeight = tooltipEl.offsetHeight;

      let left = param.point.x;
      let top = param.point.y;

      // Keep tooltip within container bounds
      if (left + tooltipWidth + 16 > containerRect.width) {
        left = left - tooltipWidth - 16;
      } else {
        left = left + 16;
      }

      if (top + tooltipHeight + 8 > containerRect.height) {
        top = top - tooltipHeight - 8;
      } else {
        top = top + 8;
      }

      tooltipEl.style.left = `${left}px`;
      tooltipEl.style.top = `${top}px`;
    });

    // --- Store Subscription ---
    let previousDataLength = 0;
    let hasReceivedData = false;

    chartStore.subscribe((points: ChartPoint[]) => {
      if (points.length === 0) return;

      // Convert ChartPoint[] to lightweight-charts format
      // ChartPoint.time is a Unix timestamp in milliseconds
      // lightweight-charts expects UTCTimestamp in seconds
      const chartData = points.map((point) => ({
        time: (point.time / 1000) as import('lightweight-charts').UTCTimestamp,
        value: point.value,
      }));

      if (!hasReceivedData) {
        // First data load ‚Äî set all data at once
        areaSeries.setData(chartData);
        chart.timeScale().fitContent();
        hasReceivedData = true;

        // Set aria-hidden on any newly created canvas elements
        container.querySelectorAll('canvas').forEach((canvas) => {
          canvas.setAttribute('aria-hidden', 'true');
        });

        // Trigger draw animation (fade-in)
        requestAnimationFrame(() => {
          container.classList.add('chart-ready');
        });
      } else if (points.length > previousDataLength) {
        // Incremental update ‚Äî append only new points
        // Use update() for the latest point to avoid full redraw
        const newPoints = chartData.slice(previousDataLength);
        for (const point of newPoints) {
          areaSeries.update(point);
        }
        chart.timeScale().fitContent();
      } else {
        // Data replaced entirely (e.g., fresh fetch cycle)
        areaSeries.setData(chartData);
        chart.timeScale().fitContent();
      }

      previousDataLength = points.length;
    });
  }
</script>
```

### lightweight-charts v5 API Reference

**Imports (v5 breaking change from v4):**

In lightweight-charts v5, series types are imported as named exports and passed to `chart.addSeries()`:

```typescript
// v5 API ‚Äî correct
import { createChart, AreaSeries } from 'lightweight-charts';
const chart = createChart(container, options);
const series = chart.addSeries(AreaSeries, seriesOptions);

// v4 API ‚Äî WRONG, do NOT use
// const series = chart.addAreaSeries(options); // REMOVED in v5
```

**Data format for area series:**

```typescript
// lightweight-charts expects { time: UTCTimestamp, value: number }
// UTCTimestamp is seconds since epoch (NOT milliseconds)
// ChartPoint.time is milliseconds ‚Äî must divide by 1000
const data = points.map((p) => ({
  time: (p.time / 1000) as UTCTimestamp,
  value: p.value,
}));
```

**Setting data vs updating:**

```typescript
// Initial load ‚Äî set all data at once
areaSeries.setData(chartData);

// Incremental update ‚Äî append new point without full redraw
areaSeries.update({ time: newTimestamp, value: newPrice });
```

The `update()` method adds a new data item or updates the latest item if times match. The time of the new item must be >= the latest existing time. This avoids full chart redraw and prevents flicker.

**Auto-resize:**

```typescript
const chart = createChart(container, {
  autoSize: true,  // Uses ResizeObserver internally
});
```

Setting `autoSize: true` makes the chart watch its container size and resize automatically. No manual `ResizeObserver` setup needed. The chart ignores explicit `resize()` calls when `autoSize` is active.

**Crosshair move subscription:**

```typescript
chart.subscribeCrosshairMove((param: MouseEventParams) => {
  if (!param.point || !param.time) {
    // Crosshair left the chart area ‚Äî hide tooltip
    return;
  }

  // Get data for our series at the crosshair position
  const data = param.seriesData.get(areaSeries) as SingleValueData | undefined;
  if (!data) return;

  // data.value contains the price at this position
  // param.time contains the time (UTCTimestamp or BusinessDay)
  // param.point.x / param.point.y contain pixel coordinates
});
```

