### Exact Implementation

```typescript
// src/lib/services/market-data-service.ts

import { marketStore } from '../stores/market-store';
import { chartStore } from '../stores/chart-store';
import type { MarketData, ChartPoint } from '../types';

// --- Constants ---

const COINGECKO_MARKETS_URL =
  'https://api.coingecko.com/api/v3/coins/markets?vs_currency=usd&ids=bitcoin&price_change_percentage=24h';

const COINGECKO_MARKET_CHART_URL =
  'https://api.coingecko.com/api/v3/coins/bitcoin/market_chart?vs_currency=usd&days=1';

const REST_POLL_INTERVAL_MS = 60_000; // 60 seconds (NFR11)

const MAX_CHART_POINTS = 24;

// --- Raw API response types ---

interface CoinGeckoMarketItem {
  market_cap: number;
  price_change_24h: number;
  price_change_percentage_24h: number;
  high_24h: number;
  low_24h: number;
}

interface CoinGeckoMarketChartResponse {
  prices: [number, number][];
}

// --- Service state ---

let timerId: ReturnType<typeof setTimeout> | null = null;
let abortController: AbortController | null = null;

// --- Data fetching ---

async function fetchMarketData(signal: AbortSignal): Promise<void> {
  try {
    const response = await fetch(COINGECKO_MARKETS_URL, { signal });

    if (!response.ok) {
      console.warn(
        `[MarketDataService] ${COINGECKO_MARKETS_URL} responded with ${response.status}`
      );
      return; // retain last store value
    }

    const data: CoinGeckoMarketItem[] = await response.json();

    if (!Array.isArray(data) || data.length === 0) {
      console.warn('[MarketDataService] Empty or invalid markets response');
      return;
    }

    const coin = data[0];

    const marketData: MarketData = {
      marketCap: coin.market_cap,
      change24h: coin.price_change_24h,
      changePercent24h: coin.price_change_percentage_24h,
      high24h: coin.high_24h,
      low24h: coin.low_24h,
    };

    marketStore.set(marketData);
  } catch (error: unknown) {
    // AbortError is expected during cleanup ‚Äî don't warn
    if (error instanceof DOMException && error.name === 'AbortError') return;
    console.warn('[MarketDataService] Failed to fetch market data:', error);
    // Stores retain their last values ‚Äî never clear on error
  }
}

async function fetchChartData(signal: AbortSignal): Promise<void> {
  try {
    const response = await fetch(COINGECKO_MARKET_CHART_URL, { signal });

    if (!response.ok) {
      console.warn(
        `[MarketDataService] ${COINGECKO_MARKET_CHART_URL} responded with ${response.status}`
      );
      return; // retain last store value
    }

    const data: CoinGeckoMarketChartResponse = await response.json();

    if (!data.prices || !Array.isArray(data.prices)) {
      console.warn('[MarketDataService] Invalid market chart response');
      return;
    }

    // Map raw [timestamp, price] tuples to ChartPoint[]
    const allPoints: ChartPoint[] = data.prices.map(
      ([time, value]: [number, number]) => ({ time, value })
    );

    // Cap at MAX_CHART_POINTS ‚Äî take the most recent entries
    const chartPoints =
      allPoints.length > MAX_CHART_POINTS
        ? allPoints.slice(-MAX_CHART_POINTS)
        : allPoints;

    chartStore.set(chartPoints);
  } catch (error: unknown) {
    if (error instanceof DOMException && error.name === 'AbortError') return;
    console.warn('[MarketDataService] Failed to fetch chart data:', error);
    // Stores retain their last values ‚Äî never clear on error
  }
}

// --- Polling ---

async function poll(): Promise<void> {
  if (!abortController) return;

  const signal = abortController.signal;

  // Fetch both in parallel ‚Äî one failure doesn't block the other
  await Promise.allSettled([
    fetchMarketData(signal),
    fetchChartData(signal),
  ]);

  // Schedule next poll (recursive setTimeout, NOT setInterval)
  // Only schedule if the service hasn't been stopped during the fetch
  if (abortController && !abortController.signal.aborted) {
    // Clear any existing timer before scheduling new one (memory leak prevention)
    if (timerId !== null) {
      clearTimeout(timerId);
    }
    timerId = setTimeout(poll, REST_POLL_INTERVAL_MS);
  }
}

// --- Public API ---

export function startMarketDataService(): void {
  // Guard against double-start
  if (abortController) {
    stopMarketDataService();
  }

  abortController = new AbortController();
  poll(); // Fire immediately, don't wait 60s for first data
}

export function stopMarketDataService(): void {
  if (abortController) {
    abortController.abort();
    abortController = null;
  }

  if (timerId !== null) {
    clearTimeout(timerId);
    timerId = null;
  }
}

// Export constants and internals for testing
export {
  COINGECKO_MARKETS_URL,
  COINGECKO_MARKET_CHART_URL,
  REST_POLL_INTERVAL_MS,
  MAX_CHART_POINTS,
  fetchMarketData,
  fetchChartData,
};
```

