    const warnSpy = vi.spyOn(console, 'warn').mockImplementation(() => {});

    mockFetch.mockResolvedValueOnce({
      ok: false,
      status: 429,
    });

    await fetchMarketData(createSignal());

    expect(marketStore.get()!.marketCap).toBe(1000000000000);
    expect(warnSpy).toHaveBeenCalledWith(
      expect.stringContaining('responded with 429')
